function solve(nums: number[]): boolean {
    const n = nums.length;

    const leftInc = new Array(n).fill(false);
    leftInc[0] = true;
    for (let i = 1; i < n; i++) {
        if (nums[i] > nums[i-1]) {
            leftInc[i] = leftInc[i-1];
        } else {
            leftInc[i] = false;
        }
    }

    const rightInc = new Array(n).fill(false);
    rightInc[n-1] = true;
    for (let i = n-2; i >= 0; i--) {
        if (nums[i] < nums[i+1]) {
            rightInc[i] = rightInc[i+1];
        } else {
            rightInc[i] = false;
        }
    }

    const isDec: boolean[][] = new Array(n);
    for (let i = 0; i < n; i++) {
        isDec[i] = new Array(n).fill(false);
    }

    for (let start = 0; start < n; start++) {
        isDec[start][start] = true;
        for (let end = start+1; end < n; end++) {
            if (isDec[start][end-1] && nums[end-1] > nums[end]) {
                isDec[start][end] = true;
            } else {
                isDec[start][end] = false;
            }
        }
    }

    for (let p = 1; p <= n-3; p++) {
        for (let q = p+1; q <= n-2; q++) {
            if (leftInc[p] && isDec[p][q] && rightInc[q]) {
                return true;
            }
        }
    }

    return false;
}
